const query = $input.first().json.query || {};
const jobId = query.jobId || $input.first().json.jobId || '';

if (!jobId || jobId.trim() === '') {
  throw new Error('Missing required query parameter: jobId');
}

return [{ json: { jobId: jobId.trim() } }];

const jobId = $('Validate Query Params').item.json.jobId;
const items = $input.all();

// No rows returned = job not found
if (!items || items.length === 0 || !items[0].json || !items[0].json.id) {
  return [{
    json: {
      responseCode: 404,
      responseBody: JSON.stringify({
        error: 'Job not found',
        jobId
      })
    }
  }];
}

const job = items[0].json;

const response = {
  jobId: job.id,
  status: job.status,
  repoName: job.repoName,
  repoUrl: job.repoUrl,
  owner: job.owner,
  createdAt: job.createdAt,
  updatedAt: job.updatedAt
};

// Only include analysisResult when COMPLETED
if (job.status === 'COMPLETED' && job.analysisResult) {
  response.analysisResult = typeof job.analysisResult === 'string'
    ? JSON.parse(job.analysisResult)
    : job.analysisResult;
}

// Include error hint on FAILED
if (job.status === 'FAILED') {
  response.errorHint = 'Analysis failed. Check that the repository is accessible with the provided token and try again.';
  if (job.analysisResult && job.analysisResult.insights) {
    const errInsight = job.analysisResult.insights.find(i => i.type === 'error');
    if (errInsight) response.errorDetail = errInsight.text;
  }
}

return [{
  json: {
    responseCode: 200,
    responseBody: JSON.stringify(response)
  }
}];
